var seed = GetInt(parameters, "seed", context.Seed);
var scale = GetFloat(parameters, "scale", 2f);
var veinFreq = GetFloat(parameters, "veinFrequency", 4f);
var veinSharpness = GetFloat(parameters, "veinSharpness", 0.5f);
var veinColor = GetColor(parameters, "veinColor", Color.FromRgb(80, 80, 80));
var bgColor = GetColor(parameters, "bgColor", Color.FromRgb(240, 240, 235));
var distortion = GetFloat(parameters, "distortion", 2f);
var octaves = Math.Max(1, GetInt(parameters, "octaves", 4));
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var vR = veinColor.R / 255f; var vG = veinColor.G / 255f; var vB = veinColor.B / 255f;
var bR = bgColor.R / 255f; var bG = bgColor.G / 255f; var bB = bgColor.B / 255f;
var period = Math.Max(1, (int)MathF.Round(scale));

buffer.ParallelForEachPixel((x, y) =>
{
    var u = x / (float)size;
    var v = y / (float)size;

    // Fractal noise for distortion
    var noiseVal = TileableFractalNoise(
        u * scale, v * scale,
        period, octaves, 0.6f, 2.2f, seed);

    // Sine wave with noise perturbation creates vein pattern
    var pattern = MathF.Sin((u * veinFreq + noiseVal * distortion) * MathF.PI * 2f);

    // Second direction for cross-veining
    var noiseVal2 = TileableFractalNoise(
        u * scale * 1.3f + 10f, v * scale * 1.3f + 10f,
        period, octaves - 1, 0.5f, 2f, seed + 500);
    var pattern2 = MathF.Sin((v * veinFreq * 0.7f + noiseVal2 * distortion * 0.8f) * MathF.PI * 2f);

    // Combine patterns
    var combined = (pattern + pattern2) * 0.5f;

    // Apply sharpness
    combined = MathF.Pow(MathF.Abs(combined), 1f - veinSharpness * 0.8f);
    combined = Math.Clamp(combined * 0.5f + 0.5f, 0f, 1f);

    // Fine detail noise for stone texture
    var detail = TileableFractalNoise(
        u * scale * 8f, v * scale * 8f,
        Math.Max(1, period / 4), 2, 0.5f, 2f, seed + 300);
    var fineGrain = (detail - 0.5f) * 0.08f;

    if (invert) combined = 1f - combined;

    var r = Math.Clamp(Lerp(bR, vR, combined) + fineGrain, 0f, 1f);
    var g = Math.Clamp(Lerp(bG, vG, combined) + fineGrain, 0f, 1f);
    var b = Math.Clamp(Lerp(bB, vB, combined) + fineGrain, 0f, 1f);

    buffer.SetPixel(x, y, r, g, b, 1f);
});

return buffer;
}
